1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	const cellOf = (key: string): Cell =>
5	  key.split(",").map(Number) as Cell;
6	
7	const neighborOffsets: Cell[] = [
8	  [-1, -1], [-1, 0], [-1, 1],
9	  [ 0, -1],          [ 0, 1],
10	  [ 1, -1], [ 1, 0], [ 1, 1],
11	];
12	
13	const neighborsOf = ([x, y]: Cell): Cell[] =>
14	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const live = new Set(cells.map(keyOf));
18	
19	  const neighborCounts = new Map<string, number>();
20	  for (const cell of cells) {
21	    for (const neighbor of neighborsOf(cell)) {
22	      const k = keyOf(neighbor);
23	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
24	    }
25	  }
26	
27	  // Conway's rule, simplified: a cell lives next gen if it has exactly 3
28	  // neighbors, or if it is already alive with exactly 2 neighbors.
29	  const survives = (k: string, count: number): boolean =>
30	    count === 3 || (count === 2 && live.has(k));
31	
32	  return Array.from(neighborCounts).flatMap(([k, count]) =>
33	    survives(k, count) ? [cellOf(k)] : []
34	  );
35	}
